INSERT OR IGNORE INTO posts (id, requestId, editOfId, title, excerpt, content, author, category, date, postedAt, images, status, reviewerNotes, attachments, authorPassword, authorEmail, satellite, areaOfInterest)
VALUES ('post-u41x0pomx', 'req-eex20s6n6', NULL, 'A Sentinel-2 Perspective of Kovilpatti''s Landscape', '', '<p>On January 22, 2026, the Sentinel-2 L2A satellite captured a clear view of Kovilpatti, Tamil Nadu, showing a mix of urban areas, agriculture, and infrastructure. The image highlights key features such as the large solar panel installation in the east and the Upper River flowing in the north, giving a useful overview of the region''s landscape.</p><p>The urban areas of Kovilpatti and Ettaiyapuram appear as dense grey patches, standing out from the surrounding rural fields. Nearby landmarks like National Engineering College and Nalattinputhur are also visible, marking important local hubs.</p><p>Around these towns, agricultural fields form a patchwork of green and brown shades, indicating active farming typical of this region. These variations reflect different crop stages and land use, providing a snapshot of the area''s agricultural activity.</p>', 'Tharun G', 'Urban GIS & Planning, Land Cover Change', '3/18/2026', '2026-03-18T17:55:55.402Z', '["https://pub-3875c56f1a994a059b1facca8711a66c.r2.dev/uploads/1773856507182-sentinel_2_kovilpatti_data_.png"]', 'published', NULL, '[]', '$2b$10$Ql.hih7V8V87vf1lrWYC4.2il9BVQB0zy9nx9HazMk5u3pvABlxY6', 'tarun.ganapathi2007@gmail.com', 'Sentinel-2', 'Kovilpatti');
